// Cross-course mastery rollup (v5.7.0).
$string['pedagogy:crossmastery'] = 'Activer par défaut le récapitulatif de maîtrise inter-cours';
$string['pedagogy:crossmastery_desc'] = 'Lorsque cette option est activée, [[tutorshort]] reconnaît qu\'un apprenant a déjà maîtrisé un objectif dans un autre cours (mis en correspondance par référence de compétence ou par titre) et prend acte de cette compétence acquise au lieu de la faire travailler à nouveau. Nécessite le suivi de la maîtrise ; les cours sans objectifs reviennent à un comportement de repli sans incident. À titre indicatif uniquement : cette option ne modifie jamais le score de maîtrise enregistré d\'un apprenant dans aucun cours.';
$string['pedagogy:mastery_starter'] = 'Activer par défaut l\'amorce tenant compte de la maîtrise';
$string['pedagogy:mastery_starter_desc'] = 'Lorsque cette option est activée, l\'amorce de conversation « Sur quoi devrais-je me concentrer ? » est personnalisée afin de nommer l\'objectif le plus faible de l\'apprenant (ainsi que toute compétence déjà maîtrisée ailleurs). Nécessite le suivi de la maîtrise ; revient à l\'amorce générique lorsqu\'aucune donnée de maîtrise n\'est encore disponible.';
$string['task:rebuild_objective_links'] = 'Reconstruire les liens d\'objectifs inter-cours pour le récapitulatif de maîtrise (v5.7.0)';
$string['mastery_starter:practice_label'] = 'S\'exercer : {$a}';
$string['objectives:rebuild_links_heading'] = 'Liens de maîtrise inter-cours';
$string['objectives:rebuild_links_help'] = '[[tutorshort]] relie les objectifs qui correspondent d\'un cours à l\'autre (par référence de compétence ou par titre) afin qu\'un apprenant ayant maîtrisé un sujet ailleurs ne le retravaille pas. Les liens sont reconstruits automatiquement chaque nuit ; utilisez ce bouton pour les reconstruire immédiatement après avoir modifié des objectifs.';
$string['objectives:rebuild_links_button'] = 'Reconstruire les liens maintenant';
$string['objectives:rebuild_links_done'] = 'Liens de maîtrise inter-cours reconstruits : {$a->total} au total ({$a->ref} par référence, {$a->exact} par titre exact, {$a->fuzzy} par titre approximatif).';

// Forward learning-path awareness (v5.8.0).
$string['pedagogy:program_path'] = 'Conscience du parcours d\'apprentissage à venir activée par défaut';
$string['pedagogy:program_path_desc'] = 'Lorsque cette option est activée, [[tutorshort]] peut indiquer à un apprenant vers quoi mène le cours actuel dans son programme (diplôme ou certificat) et comment les concepts du jour préparent les cours ultérieurs. Elle lit le plugin Programs de Moodle (Degrees et Learn) et ne nomme un cours suivant précis que lorsque le programme définit un prérequis ou un ordre obligatoire ; sinon, elle situe simplement la position de l\'apprenant dans le parcours. À titre consultatif uniquement — elle ne modifie jamais l\'inscription ni la maîtrise, et n\'utilise que l\'attribution de programme propre à l\'apprenant actuel. Ne fait rien, de manière silencieuse, lorsqu\'aucun programme ne s\'applique.';

// Learning path map + next-course nudge (v5.9.0).
$string['pedagogy:learning_path'] = 'Carte du parcours d\'apprentissage et suggestion du cours suivant activées par défaut';
$string['pedagogy:learning_path_desc'] = 'Lorsqu\'elle est activée, [[tutorshort]] ajoute un panneau visuel de parcours d\'apprentissage (un bouton "mon parcours" dans l\'en-tête du widget) montrant le programme de l\'apprenant sous forme de séquence de cours, chacun pouvant être déployé pour afficher ses objectifs et la maîtrise de l\'apprenant. Lorsque l\'apprenant a atteint le seuil du cours actuel (achèvement ou une part élevée d\'objectifs maîtrisés), [[tutorshort]] affiche également une bannière discrète "prêt pour le cours suivant" et le mentionne dans la conversation. À titre indicatif uniquement ; utilise l\'affectation de programme propre à l\'apprenant ; ne fait rien silencieusement lorsqu\'aucun programme ne s\'applique.';
$string['settings:learning_path_mastery_threshold'] = 'Seuil de préparation du parcours d\'apprentissage (%)';
