// v5.10.x strings (token-aware budgeting, backend retry, self-test, deployment presets, escalation consent, privacy).
$string['settings:backend_context_tokens'] = 'Fenêtre de contexte du backend (jetons)';
$string['settings:backend_context_tokens_desc'] = 'La longueur de contexte maximale (max_model_len) de votre backend d\'IA, en jetons. Définissez 0 pour les modèles hébergés disposant d\'une grande fenêtre (aucun bridage). Lorsqu\'elle est supérieure à 0 (par exemple 8192 sur un backend vLLM auto-hébergé), [[tutorshort]] réduit le budget de caractères de l\'invite système ci-dessus afin que l\'invite, ainsi que la sortie réservée et l\'historique de conversation, tiennent dans la fenêtre, même dans les langues à forte densité de jetons. Consultez la page wiki Deployment Sizing pour savoir comment cela se traduit en utilisateurs simultanés.';
$string['settings:backend_retry_attempts'] = 'Tentatives de réessai du backend';
$string['settings:backend_retry_attempts_desc'] = 'Le nombre de fois où réessayer une erreur transitoire du backend (HTTP 429 ou 503) avant d\'afficher une erreur à l\'étudiant. Les réessais n\'ont lieu qu\'avant qu\'un texte de réponse n\'ait été diffusé, de sorte que la sortie n\'est jamais dupliquée. Destiné aux petits backends auto-hébergés qui rejettent les requêtes en cas de charge. Définissez 0 pour désactiver. Par défaut 2.';
$string['settings:backend_retry_max_wait'] = 'Attente maximale de réessai du backend (secondes)';
$string['settings:backend_retry_max_wait_desc'] = 'Limite supérieure, en secondes, du temps pendant lequel honorer un en-tête Retry-After du backend avant de réessayer. Lorsque le backend n\'envoie aucun Retry-After, [[tutorshort]] utilise à la place un court délai exponentiel. Par défaut 5.';
$string['prompt:truncation_hint'] = 'REMARQUE : L\'intégralité du contenu du cours n\'a pas pu être recherchée ce tour-ci en raison de limites de longueur. Si l\'étudiant pose une question sur un élément que vous ne trouvez pas dans le contenu fourni, indiquez que vous n\'avez pas pu rechercher l\'ensemble du cours et suggérez d\'ouvrir la page ou l\'activité spécifique où le sujet est traité, plutôt que d\'affirmer qu\'il est absent du cours.';
$string['selftest:title'] = 'Autotest du backend';
$string['selftest:intro'] = 'Exécutez une vérification en direct de votre backend d\'IA configuré : un petit aller-retour de chat, la détection automatique de la fenêtre de contexte (max_model_len) et une comparaison avec votre paramètre Fenêtre de contexte du backend, le plancher du budget de l\'invite système et (lorsque RAG est activé) un aller-retour d\'embedding. Les appels réseau ne s\'exécutent que lorsque vous appuyez sur Exécuter.';
$string['selftest:run'] = 'Exécuter l\'autotest du backend';
