$string['settings:zendesk_require_consent'] = 'Exiger le consentement avant l\'escalade vers le support';
$string['settings:zendesk_require_consent_desc'] = 'Lorsqu\'il est activé (recommandé), [[tutorshort]] n\'escalade une conversation vers le service de support Zendesk qu\'après que l\'apprenant a accepté l\'avis de consentement de première utilisation, qui indique que demander une aide humaine partage la conversation (y compris le nom et l\'e-mail) avec le support. Désactivez cette option uniquement si vous obtenez ce consentement d\'une autre manière ; lorsqu\'elle est désactivée, les escalades sont envoyées immédiatement. N\'a aucun effet sauf si l\'escalade Zendesk est activée.';
$string['chat:escalation_needs_consent'] = 'Il semble que cela nécessite un membre de notre équipe de support. Pour le leur transmettre, je devrais partager cette conversation, y compris votre nom et votre e-mail, avec le service de support. Vous n\'avez pas encore accepté cela, je n\'ai donc rien envoyé. Si vous souhaitez une aide humaine, veuillez accepter l\'avis de partage de données de cet assistant et redemander, ou contactez directement le support.';
$string['privacy:metadata:email_optout'] = 'Préférences de désinscription par e-mail propres à chaque destinataire (les types d\'e-mails dont un destinataire s\'est désabonné).';
$string['privacy:metadata:email_optout:email'] = 'L\'adresse e-mail du destinataire à laquelle s\'applique la désinscription.';
$string['privacy:metadata:email_optout:optout_type'] = 'Le type d\'e-mail dont le destinataire s\'est désinscrit.';
$string['privacy:metadata:email_optout:userid'] = 'L\'utilisateur Moodle auquel appartient la désinscription, lorsqu\'il est connu.';
$string['chat:consent_scroll_hint'] = 'Veuillez faire défiler jusqu\'en bas pour lire l\'intégralité de l\'avis avant de continuer.';
$string['settings:rag_min_similarity'] = 'Pertinence minimale (cosinus)';
$string['settings:rag_min_similarity_desc'] = 'Écarte les fragments récupérés dont la similarité cosinus avec la question est inférieure à cette valeur, afin qu\'une question hors sujet ou peu fournie injecte moins de passages (voire aucun) au lieu de toujours compléter jusqu\'à Top-K avec des correspondances faibles. Plage de 0 à 1 ; 0 désactive le filtre. La bonne valeur dépend du modèle d\'embedding : 0.25 convient à text-embedding-3-small. Augmentez-la pour être plus strict (moins de contexte, plus centré sur le sujet), abaissez-la pour être plus permissif.';
$string['settings:rag_currentpage_boost'] = 'Bonus page actuelle';
$string['settings:rag_currentpage_boost_desc'] = 'Un petit bonus ajouté au score de pertinence des fragments de la page que l\'apprenant consulte actuellement, afin que des questions comme « explique ceci » privilégient la page visible lorsque les scores sont proches. Affecte uniquement l\'ordre : il ne force pas un fragment de page non pertinent à passer le filtre de pertinence minimale. Réglez sur 0 pour désactiver.';
$string['settings:history_mode'] = 'Mode de sélection de l\'historique';
$string['settings:history_mode_desc'] = 'Comment les tours de conversation passés sont choisis avant d\'être envoyés au modèle. <strong>Sémantique</strong> ne conserve que les tours récents pertinents pour la question actuelle (et toujours le dernier échange), afin qu\'un tour antérieur obsolète et hors sujet ne gonfle pas le coût ni ne détourne la réponse ; il effectue un appel d\'embedding supplémentaire par message. <strong>Récence</strong> conserve les derniers paires « Historique de conversation maximal » quelle que soit leur pertinence (le comportement historique, sans appel supplémentaire). Si l\'embedding n\'est pas disponible, le mode sémantique bascule automatiquement vers la récence.';
$string['settings:history_mode_semantic'] = 'Sémantique (tours récents pertinents)';
$string['settings:history_mode_recency'] = 'Récence (N dernières paires)';
$string['settings:history_semantic_minscore'] = 'Seuil de pertinence de l\'historique (cosinus)';
$string['settings:history_semantic_minscore_desc'] = 'En mode d\'historique sémantique, un tour antérieur n\'est conservé que si sa similarité avec la question actuelle est au moins égale à cette valeur (le dernier échange est toujours conservé). Plage de 0 à 1 ; dépend du modèle. Augmentez pour être plus strict (moins d\'historique), abaissez pour en conserver davantage.';
$string['settings:history_candidates'] = 'Fenêtre de candidats de l\'historique';
$string['settings:history_candidates_desc'] = 'En mode d\'historique sémantique, seules les paires les plus récentes, jusqu\'à ce nombre, sont évaluées en pertinence (une limite de coût). Les paires plus anciennes que cette fenêtre ne sont pas envoyées. Maintenez cette valeur égale ou supérieure à « Historique de conversation maximal ».';

// v5.11.0 - v6.2.0 strings (added 2026-06-10).
$string['settings:embed_provider_voyage'] = 'Voyage AI (voyage-3.5 — recommandé ; +4 MTEB vs OpenAI 3-small, 4x contexte, multilingue)';
$string['settings:rerank_heading'] = 'RAG : Récupération en deux étapes (reclassement)';
$string['settings:rerank_heading_desc'] = 'Deuxième étape de récupération optionnelle : la similarité cosinus sélectionne les N meilleurs fragments candidats (50 par défaut), puis un reclasseur à encodeur croisé note chaque paire (requête, fragment) et les meilleurs K entrent dans le prompt. Désactivé par défaut ; repasse à la similarité cosinus simple si le reclasseur n\'est pas configuré ou échoue.';
$string['settings:rerank_enabled'] = 'Récupération en deux étapes (Voyage rerank-2.5)';
$string['settings:rerank_enabled_desc'] = 'Lorsqu\'activé, la récupération RAG devient en deux étapes : la similarité cosinus renvoie les N meilleurs candidats (50 par défaut), puis l\'encodeur croisé Voyage rerank-2.5 note chacun et les K meilleurs entrent dans le prompt. Améliorations publiées : +15 Recall@10 entreprise, +39 % NDCG BEIR. ~0,05 $/MTok de facturation. Nécessite <code>rerank_apikey</code> ci-dessous ; revient gracieusement à la similarité cosinus simple si le reclassement échoue ou n\'est pas configuré.';
$string['settings:rerank_apikey'] = 'Clé API de reclassement';
$string['settings:rerank_apikey_desc'] = 'Clé API Voyage AI pour rerank-2.5. Laissez vide pour réutiliser la clé API d\'embedding ci-dessus (les déploiements Voyage typiques partagent une seule clé entre embed et rerank).';
$string['settings:rerank_model'] = 'Modèle de reclassement';
$string['settings:rerank_model_desc'] = 'Par défaut <code>rerank-2.5</code>. Des modèles de reclassement Voyage plus récents peuvent être spécifiés ici.';
$string['settings:rerank_apibaseurl'] = 'URL de base de l\'API de reclassement';
$string['settings:rerank_apibaseurl_desc'] = 'Remplace l\'URL de base de reclassement Voyage. Laissez vide pour utiliser l\'URL de base de l\'API d\'embedding ci-dessus, ou la valeur par défaut de Voyage (<code>https://api.voyageai.com/v1</code>).';
$string['settings:rerank_candidates'] = 'Fenêtre de candidats de reclassement';
$string['settings:rerank_candidates_desc'] = 'Combien de candidats cosinus N-meilleurs alimentent l\'étape de reclassement. Par défaut 50. Des fenêtres plus larges donnent au reclasseur plus de matière à traiter à un faible coût supplémentaire (~10 000 tokens par opération de reclassement).';
$string['settings:stt_selfhosted_heading'] = 'Transcription auto-hébergée (Whisper)';
$string['settings:stt_selfhosted_heading_desc'] = 'Exécutez la conversion parole-texte sur votre propre matériel à zéro coût par minute. Pointez [[tutorshort]] vers n\'importe quel serveur de transcription compatible OpenAI : Docker <code>whisper-server</code>, <code>speaches</code> (faster-whisper) ou serveur <code>whisper.cpp</code>. Lorsqu\'une URL de serveur est définie ici, elle devient le chemin STT par défaut ; sélectionnez un fournisseur payant dans Fournisseur STT actif ci-dessus pour le remplacer. Si le serveur est sur un réseau privé ou en http simple, ajoutez également son hôte à la liste blanche des points de terminaison SSRF approuvés dans la section Sécurité.';
$string['settings:stt_selfhosted_url'] = 'URL du serveur STT auto-hébergé';
$string['settings:stt_selfhosted_url_desc'] = 'URL de base du serveur de transcription compatible OpenAI, par exemple <code>http://10.0.0.5:8000</code>. [[tutorshort]] ajoute <code>/v1/audio/transcriptions</code> automatiquement ; un chemin de point de terminaison complet est également accepté. Laissez vide pour désactiver le STT auto-hébergé.';
$string['settings:stt_selfhosted_model'] = 'Modèle STT auto-hébergé';
$string['settings:stt_selfhosted_model_desc'] = 'Nom du modèle transmis au serveur, correspondant au modèle Whisper chargé — par exemple <code>Systran/faster-whisper-small</code> pour speaches ou <code>large-v3</code>. Laissez vide pour envoyer <code>whisper-1</code>, que la plupart des serveurs auto-hébergés acceptent ou ignorent.';
$string['settings:stt_selfhosted_apikey'] = 'Clé API STT auto-hébergé';
$string['settings:stt_selfhosted_apikey_desc'] = 'Optionnel. La plupart des serveurs auto-hébergés n\'ont pas besoin de clé sur un réseau de confiance ; définissez-la seulement si votre serveur requiert un token bearer.';
