$string['settings:prompt_proportions_heading'] = 'Proportions des sections du prompt (v5.6.0)';
$string['settings:prompt_proportions_heading_desc'] = 'Allouez le budget du prompt système sur quatre compartiments : sécurité + identité, structure du cours, contenu du cours et page actuelle. Les pondérations sont des pourcentages dont la somme est 100. Les valeurs par défaut calibrées empiriquement (10 / 10 / 40 / 40) proviennent du benchmark de calibrage des pondérations v5.6.0 ; laisser la zone de texte vide utilise ces valeurs par défaut. Le boost automatique ajuste l\'allocation à chaque tour selon qu\'une page spécifique est dans la portée.';
$string['settings:prompt_section_weights'] = 'Pondérations de section de base (JSON)';
$string['settings:prompt_section_weights_desc'] = 'Objet JSON optionnel associant chaque compartiment à un pourcentage. Laissez vide pour utiliser les valeurs par défaut du benchmark (10 / 10 / 40 / 40). Exemple : <code>{"safety_identity": 10, "course_structure": 10, "course_content": 40, "current_page": 40}</code>. Les pondérations doivent totaliser 100 (±5 %). <code>safety_identity</code> a un plancher de 10 % pour que la résistance aux jailbreaks et les marqueurs de format de sortie atterrissent toujours en totalité. <code>current_page + course_content</code> doit représenter au moins 40 % pour que le modèle dispose de matière substantielle sur laquelle s\'appuyer. Les valeurs hors plage reviennent silencieusement aux valeurs par défaut du benchmark ; les administrateurs doivent valider en consultant le journal de débogage des prompts après sauvegarde.';
$string['settings:prompt_context_boost_mode'] = 'Mode de boost de contexte';
$string['settings:prompt_context_boost_mode_desc'] = 'Ajustement automatique qui déplace le poids vers la section de page actuelle quand une page spécifique est dans la portée, et vers le contenu du cours quand aucune page n\'est sélectionnée. <strong>page_focus</strong> (par défaut) déplace environ 15 points de pondération. <strong>aggressive</strong> déplace 25 points et est préférable quand les apprenants posent systématiquement des questions spécifiques à une page. <strong>off</strong> désactive le boost ; les pondérations de base définies par l\'administrateur s\'appliquent à chaque tour quel que soit le contexte de page.';
$string['settings:prompt_context_boost_off'] = 'Désactivé (utiliser les pondérations de base à chaque tour)';
$string['settings:prompt_context_boost_page_focus'] = 'Focus page (par défaut, déplacement de ~15 points)';
$string['settings:prompt_context_boost_aggressive'] = 'Agressif (~25 points de déplacement)';
$string['settings:prompt_section_weights_coach'] = 'Remplacement en mode coach (JSON, optionnel)';
$string['settings:prompt_section_weights_coach_desc'] = 'Objet JSON optionnel remplaçant les pondérations de section de base spécifiquement lors du mode coach de quiz noté (quand <code>quizmode=coach</code>). Utile pour forcer une allocation <code>current_page</code> plus lourde lors des quiz sans affecter le chat normal. Laissez vide pour hériter des pondérations de base. Mêmes règles de validation que le paramètre de base.';
$string['prompt_debug_view:title'] = 'Visionneuse du journal de débogage des prompts';
$string['prompt_debug_view:subtitle'] = 'Prompt système assemblé par tour + ventilation par section + historique des conversations + message utilisateur actuel + métadonnées des pièces jointes, exactement tels que le modèle les a reçus. Utilisez ceci pour vérifier si une section comme Contenu de la page actuelle a bien été incluse dans le prompt et pour déboguer les problèmes de qualité des réponses sans connexion SSH au serveur.';
$string['prompt_debug_view:disabled'] = 'La journalisation de débogage des prompts est actuellement DÉSACTIVÉE. Aucune nouvelle entrée ne sera écrite tant qu\'elle n\'est pas activée.';
$string['prompt_debug_view:enable_link'] = 'Ouvrez les paramètres du plugin pour activer « Journaliser le prompt système assemblé dans un fichier ».';
$string['prompt_debug_view:no_log_yet'] = 'Pas encore de fichier journal. Envoyez au moins un tour de chat après avoir activé le journal de débogage ; le fichier est créé lors du premier enregistrement.';
$string['prompt_debug_view:empty'] = 'Le fichier journal existe mais est vide. Envoyez un tour de chat et actualisez.';
