$string['settings:mastery_classifier_provider'] = 'Fournisseur du classificateur';
$string['settings:mastery_classifier_provider_desc'] = 'Identifiant du fournisseur utilisé pour le classificateur de maîtrise par tour. Laissez vide pour hériter du fournisseur d\'IA par défaut. La valeur par défaut <code>openai</code> est associée au modèle classificateur <code>gpt-4o-mini</code> ci-dessous — l\'option TIER 1 la moins coûteuse pour la classification à sortie structurée (~220 $/mois d\'économies à 100 000 MAU vs le tier chat). Quand défini, la ligne dans Fournisseurs de comparaison avec cet identifiant de fournisseur fournit la clé API, l\'URL de base et la température.';
$string['settings:premium_escalation_heading'] = 'Niveau d\'escalade premium (A.10)';
$string['settings:premium_escalation_heading_desc'] = 'Routage optionnel par tour vers un modèle premium (Claude Opus 4.8 par défaut) pour les prompts où le tier chat de base peine visiblement — typiquement les mathématiques multi-étapes, CS et le raisonnement scientifique. Résolu par le bake-off A.10 du 09/06/2026 : Opus 4.8 a remporté 14,97/15 contre 12,68/15 pour gpt-4o sur les prompts difficiles. Deux chemins de déclenchement : correspondances regex sur le message utilisateur, OU une liste d\'autorisation de cours qui escalade à chaque tour. Désactivé par défaut. À ~5 % d\'escalade, attendez ~700 $/mois à 100 000 [[unishort]] MAU en plus des dépenses de chat de base.';
$string['settings:premium_escalation_enabled'] = 'Activer le routage d\'escalade premium';
$string['settings:premium_escalation_enabled_desc'] = 'Lorsqu\'activé, le routeur par tour vérifie la liste de regex de déclenchement et la liste d\'autorisation de cours pour chaque appel de chat ; les tours correspondants sont acheminés vers le fournisseur premium. Revient au fournisseur de base si la ligne premium est manquante ou ne peut pas être instanciée. Les remplacements du sélecteur LLM administrateur l\'emportent toujours quoi qu\'il arrive.';
$string['settings:premium_escalation_provider'] = 'Fournisseur premium';
$string['settings:premium_escalation_provider_desc'] = 'Identifiant du fournisseur pour router les appels premium. Doit correspondre à une ligne dans Fournisseurs de comparaison (pour que la clé API, l\'URL de base et la température proviennent du même endroit que les administrateurs gèrent déjà). Par défaut <code>claude</code>.';
$string['settings:premium_escalation_model'] = 'Modèle premium';
$string['settings:premium_escalation_model_desc'] = 'Nom du modèle transmis au fournisseur premium. Par défaut <code>claude-opus-4-8</code> conformément au verdict du bake-off A.10.';
$string['settings:premium_escalation_triggers'] = 'Regex de déclenchement premium';
$string['settings:premium_escalation_triggers_desc'] = 'Un regex PCRE par ligne (sans délimiteurs ; la correspondance insensible à la casse est appliquée automatiquement). Les lignes commençant par # sont des commentaires. Laissez vide pour utiliser l\'ensemble par défaut sélectionné du bake-off A.10 (marqueurs STEM multi-étapes : "derive", "prove that", "step by step", LaTeX math, blocs de code délimités, big-O, intégrales, optimisation, etc.).';
$string['settings:premium_escalation_course_tags'] = 'Liste d\'autorisation de cours premium';
$string['settings:premium_escalation_course_tags_desc'] = 'Un nom court de cours ou préfixe d\'idnumber par ligne. Chaque tour dans un cours correspondant est automatiquement escaladé quel que soit le regex du message (à utiliser pour les cours à forte composante STEM où l\'escalade doit être le comportement par défaut). La correspondance est insensible à la casse par préfixe — "MATH" correspond à MATH121, MATH205, etc.';
$string['settings:spend_cap_per_course_default'] = 'Plafond de dépenses par cours par défaut (USD)';
$string['settings:spend_cap_per_course_default_desc'] = 'Plafond défensif appliqué à chaque cours qui n\'a pas son propre plafond de dépenses par cours configuré. Définissez par exemple <code>30</code> pour limiter les dépenses mensuelles de tout cours individuel à 30 $ sans avoir à régler les cours un par un. <code>0</code> = pas de plafond par défaut (seuls les plafonds au niveau du site et les remplacements par cours s\'appliquent). Lorsqu\'un cours dépasse 80 % / 95 % / 100 % de ce plafond, le pipeline d\'alertes spend-guard existant envoie la notification administrateur (liste des destinataires : <code>spend_notify_emails</code>, revenant aux administrateurs du site). Un cours spécifique peut toujours relever son propre plafond en définissant un remplacement par cours plus élevé.';
$string['settings:cost_anomaly_heading'] = 'Détecteur d\'anomalie de coûts (v6.0)';
$string['settings:cost_anomaly_heading_desc'] = 'Tâche planifiée quotidienne (<code>cost_anomaly_check</code>) qui compare les dépenses [[tutorshort]] du site d\'aujourd\'hui à la médiane glissante sur 7 jours. Envoie un e-mail à la liste de destinataires <code>spend_notify_emails</code> (revenant aux administrateurs du site) quand aujourd\'hui dépasse le multiplicateur configuré × la médiane. Détecte trois modes de défaillance que les seuils 80 % / 95 % / 100 % du plafond de dépenses existant ne détectent pas : (1) cours emballé où le plafond absolu n\'est pas franchi mais un seul cours génère soudainement 10 fois son volume habituel, (2) activation accidentelle du tier premium, (3) mauvais routage fournisseur. Désactivé par défaut ; l\'équivalent interne à [[tutorshort]] de la requête Redash de <code>.drafts/sola-redash-cost-anomaly-2026-06-09.md</code>.';
$string['settings:cost_anomaly_enabled'] = 'Activer le détecteur d\'anomalie de coûts';
$string['settings:cost_anomaly_enabled_desc'] = 'Lorsqu\'activé, la tâche planifiée quotidienne évalue les dépenses d\'aujourd\'hui par rapport à la médiane glissante sur 7 jours et envoie un e-mail aux administrateurs en cas d\'anomalie. Les 7 premiers jours après l\'activation produisent un statut <code>insufficient_history</code> (pas encore de référence historique) et n\'émettent jamais d\'alerte. Idempotent par jour : un drapeau dans <code>config_plugins</code> empêche les e-mails répétés si cron s\'exécute plusieurs fois.';
$string['settings:cost_anomaly_multiplier'] = 'Multiplicateur d\'anomalie';
$string['settings:cost_anomaly_multiplier_desc'] = 'Les dépenses d\'aujourd\'hui doivent dépasser ce multiplicateur × la médiane sur 7 jours pour déclencher une alerte. Par défaut <code>2.0</code>. Abaissez à <code>1.5</code> pour des avertissements plus précoces (plus de faux positifs lors des pics d\'inscription). Augmentez à <code>3.0</code> si l\'utilisation de [[unishort]] est suffisamment irrégulière pour que des pics de 2x soient habituels.';
$string['task:cost_anomaly_check'] = 'Vérification des anomalies de coûts [[tutorshort]] (quotidienne)';

// v6.4.0 signed policy bundle strings (added 2026-06-11).
$string['settings:policy_bundle_heading'] = 'Pack de politiques signé (mises à jour du comportement à distance)';
$string['settings:policy_bundle_heading_desc'] = 'Appliquez des paramètres de comportement (invites, routage, déclencheurs d\'escalade, réglage RAG, politique de dépenses) depuis un fichier JSON signé cryptographiquement sans déploiement de code. Une tâche planifiée quotidienne récupère l\'URL du pack, vérifie sa signature Ed25519 par rapport à la clé publique ci-dessous et applique les paramètres uniquement si chaque clé figure dans la liste d\'autorisation intégrée et si la version du pack est plus récente que la dernière appliquée. Les clés API, les URL, les webhooks et les paramètres de sécurité ne peuvent jamais être définis par un pack. Créez et signez des packs avec <code>admin/cli/policy_bundle_tool.php</code> (keygen, sign, verify, status, sync).';
$string['settings:policy_bundle_enabled'] = 'Activer la synchronisation du pack de politiques';
$string['settings:policy_bundle_enabled_desc'] = 'Lorsqu\'activée, la tâche quotidienne récupère et applique les packs signés. Désactivée par défaut. La désactivation arrête immédiatement toutes les synchronisations ; les paramètres déjà appliqués conservent leurs valeurs.';
$string['settings:policy_bundle_url'] = 'URL du pack de politiques';
$string['settings:policy_bundle_url_desc'] = 'URL HTTPS du JSON du pack signé (par exemple un objet S3 ou GitHub raw URL). L\'URL est soumise à la même validation SSRF que les points de terminaison des fournisseurs d\'IA ; les hôtes de réseau privé ou plain-http nécessitent une entrée dans la liste d\'autorisation des points de terminaison SSRF de confiance.';
$string['settings:policy_bundle_pubkey'] = 'Clé publique du pack de politiques';
$string['settings:policy_bundle_pubkey_desc'] = 'Clé publique Base64 Ed25519 utilisée pour vérifier les signatures du pack. Générez la paire de clés avec <code>policy_bundle_tool.php --keygen</code> ; la clé privée reste chez l\'auteur du pack et ne doit jamais être téléchargée nulle part.';
$string['settings:policy_bundle_status'] = 'Dernière synchronisation';
$string['settings:policy_bundle_applied_version'] = 'version appliquée';
$string['task:policy_bundle_sync'] = 'Synchronisation du pack de politiques signé [[tutorshort]]';
$string['policy_bundle:invalid'] = 'Pack de politiques rejeté : {$a}';
$string['prompt_debug_view:retrieved_chunks'] = 'Segments récupérés (sélection RAG)';
$string['prompt_debug_view:retrieved_chunks_hint'] = 'Les passages que le récupérateur a sélectionnés pour cette question, classés par ordre de pertinence avec leur score de pertinence et leur source (cmid). Utilisez ceci pour vérifier que le modèle a reçu le contenu de cours le plus pertinent.';
$string['settings:avatar_animation_enabled'] = 'Animation de l\'avatar';
